import '../../core/channel/navivox_channel.dart';
import 'count_labels.dart';
import 'profile_health_labels.dart';

String profileContactDisplayLabel(
  NavivoxProfileContact? contact, {
  required String fallback,
}) {
  final displayName = contact?.displayName.trim();
  if (displayName != null && displayName.isNotEmpty) return displayName;
  return fallback;
}

String profileContactServerLabel(
  NavivoxProfileContact? contact, {
  required String fallback,
}) {
  final label = contact?.serverLabel.trim();
  if (label != null && label.isNotEmpty) return label;
  return fallback;
}

List<String> profileContactProjectStatusSegments(
  NavivoxProfileContact profile,
) {
  final segments = <String>[];
  if (profile.workspaceRootCount > 0) {
    segments.add(countLabel(profile.workspaceRootCount, 'project'));
  }
  if (profile.workspaceRootsError > 0) {
    segments.add(countLabel(profile.workspaceRootsError, 'error'));
  }
  if (profile.workspaceRootsWarning > 0) {
    segments.add(countLabel(profile.workspaceRootsWarning, 'warning'));
  }
  if (segments.isEmpty && !profile.workspaceRootsOk) {
    segments.add('project attention needed');
  }
  return segments;
}

String profileContactProjectStatusLabel(NavivoxProfileContact profile) {
  return profileContactProjectStatusSegments(profile).join(' • ');
}

String profileContactStatusBarLabel(NavivoxProfileContact profile) {
  return [
    profile.serverLabel,
    profileHealthLabel(profile.health),
    ...profileContactProjectStatusSegments(profile),
  ].join(' • ');
}

import 'package:flutter_test/flutter_test.dart';
import 'package:navivox/core/channel/navivox_channel.dart';
import 'package:navivox/shared/presentation/profile_contact_labels.dart';

void main() {
  const profile = NavivoxProfileContact(
    serverId: 'srv1',
    profileId: 'mineru',
    displayName: 'Mineru Builder',
    serverLabel: 'Local',
    health: NavivoxProfileHealth.warning,
    latestPreview: 'Ready',
    workspaceRootCount: 4,
    workspaceRootsWarning: 2,
    workspaceRootsError: 1,
  );

  test('uses safe profile and server fallbacks for blank contacts', () {
    const blankContact = NavivoxProfileContact(
      serverId: 'srv1',
      profileId: 'mineru',
      displayName: ' ',
      serverLabel: ' ',
      health: NavivoxProfileHealth.online,
      latestPreview: 'Ready',
    );

    expect(
      profileContactDisplayLabel(blankContact, fallback: 'mineru'),
      'mineru',
    );
    expect(profileContactServerLabel(blankContact, fallback: 'default'), 'default');
    expect(profileContactDisplayLabel(null, fallback: 'default'), 'default');
    expect(profileContactServerLabel(null, fallback: 'default'), 'default');
  });

  test('formats project status segments and full status bar labels', () {
    expect(profileContactProjectStatusSegments(profile), [
      '4 projects',
      '1 error',
      '2 warnings',
    ]);
    expect(
      profileContactProjectStatusLabel(profile),
      '4 projects • 1 error • 2 warnings',
    );
    expect(
      profileContactStatusBarLabel(profile),
      'Local • warning • 4 projects • 1 error • 2 warnings',
    );
  });

  test('reports project attention when no counts exist but roots are unhealthy', () {
    const profile = NavivoxProfileContact(
      serverId: 'srv1',
      profileId: 'mineru',
      displayName: 'Mineru Builder',
      serverLabel: 'Local',
      health: NavivoxProfileHealth.online,
      latestPreview: 'Ready',
      workspaceRootsOk: false,
    );

    expect(profileContactProjectStatusSegments(profile), [
      'project attention needed',
    ]);
    expect(
      profileContactStatusBarLabel(profile),
      'Local • online • project attention needed',
    );
  });
}

